import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface CandlestickData {
  date: string;
  open: number;
  high: number;
  low: number;
  close: number;
}

interface VolumeData {
  date: string;
  volume: number;
}

interface StockData {
  symbol: string;
  companyName: string;
  candlestickData: CandlestickData[];
  volumeData: VolumeData[];
}

export default function Widget() {
  const stockData = response.data as StockData;
  const { symbol, companyName, candlestickData, volumeData } = stockData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1F2937' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#94A3B8' }}>
              {companyName} ({symbol})
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: volumeData.map(v => v.volume),
                  color: '#FF5252',
                  label: 'Volume',
                },
                {
                  type: 'line',
                  data: candlestickData.map(c => c.close),
                  color: '#0D47A1',
                  label: 'Close Price',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: candlestickData.map(c => c.date),
                  id: 'dates',
                },
              ]}
              yAxis={[{ id: 'price' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="dates"
                tickLabelStyle={{ fontSize: 10, fill: '#9CA3AF' }}
              />
              <ChartsYAxis
                axisId="price"
                tickLabelStyle={{ fontSize: 10, fill: '#9CA3AF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Typography variant="caption" sx={{ color: '#9CA3AF', textAlign: 'center' }}>
            Data for the past 10 days
          </Typography>
        </Stack>
      </CardContent>
    </Card>
  );
}
